import{c as a,Q as t,j as o,m as r}from"./chunks/framework.Cmzu3bfV.js";const p=JSON.parse('{"title":"Requisitos para Instalação em Nuvem (Cloud)","description":"","frontmatter":{},"headers":[],"relativePath":"versoes/2026-05/desbravador-41/cloud/requisitos-cloud.md","filePath":"versoes/2026-05/desbravador-41/cloud/requisitos-cloud.md","lastUpdated":1779287363000}'),i={name:"versoes/2026-05/desbravador-41/cloud/requisitos-cloud.md"};function d(s,e,n,l,c,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="requisitos-para-instalacao-em-nuvem-cloud" tabindex="-1">Requisitos para Instalação em Nuvem (Cloud) <a class="header-anchor" href="#requisitos-para-instalacao-em-nuvem-cloud" aria-label="Permalink to &quot;Requisitos para Instalação em Nuvem (Cloud)&quot;">​</a></h1><p><strong>Sistema:</strong> Desbravador 4.1 / 3.1 / 3.0 Smart<br><strong>Modalidade:</strong> Cloud — Plataforma AutoSky / Sky.One<br><strong>Público:</strong> Cliente hoteleiro / Equipe de TI</p><hr><h2 id="a-1-visao-geral" tabindex="-1">A.1 Visão Geral <a class="header-anchor" href="#a-1-visao-geral" aria-label="Permalink to &quot;A.1 Visão Geral&quot;">​</a></h2><p>A solução é implantada em ambiente cloud utilizando a plataforma da Sky.One, por meio da oferta <strong>AutoSky</strong>, garantindo alta disponibilidade, segurança e escalabilidade para operação dos sistemas.</p><p>A arquitetura é baseada em modelo virtualizado e distribuído, com camadas independentes para aplicação, banco de dados e serviços auxiliares.</p><p>O ambiente contempla:</p><ul><li>Infraestrutura em nuvem com recursos escaláveis (CPU, memória e disco).</li><li>Isolamento lógico entre ambientes (produção, homologação, testes).</li><li>Camadas independentes para aplicação e banco de dados.</li><li>Armazenamento de alto desempenho (SSD/NVMe).</li><li>Recursos de segurança: firewall, controle de acesso e monitoramento.</li></ul><hr><h2 id="a-2-provedor-cloud" tabindex="-1">A.2 Provedor Cloud <a class="header-anchor" href="#a-2-provedor-cloud" aria-label="Permalink to &quot;A.2 Provedor Cloud&quot;">​</a></h2><p>A Sky.One é responsável pela disponibilização da infraestrutura cloud:</p><ul><li>Data centers com alta disponibilidade.</li><li>Infraestrutura física (servidores, storage e rede).</li><li>Virtualização e orquestração dos recursos.</li><li>Monitoramento de infraestrutura.</li><li>Segurança perimetral.</li></ul><p>A plataforma <strong>AutoSky</strong> permite a gestão simplificada do ambiente, com provisionamento ágil e controle centralizado dos recursos.</p><hr><h2 id="a-3-modelo-de-responsabilidade-compartilhada" tabindex="-1">A.3 Modelo de Responsabilidade Compartilhada <a class="header-anchor" href="#a-3-modelo-de-responsabilidade-compartilhada" aria-label="Permalink to &quot;A.3 Modelo de Responsabilidade Compartilhada&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Responsabilidade</th><th style="text-align:center;">Sky.One / AutoSky</th><th style="text-align:center;">Desbravador</th><th style="text-align:center;">Cliente</th></tr></thead><tbody><tr><td>Infraestrutura física (hardware, energia, refrigeração)</td><td style="text-align:center;">✔</td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Rede e conectividade da plataforma cloud</td><td style="text-align:center;">✔</td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Virtualização e disponibilidade da plataforma</td><td style="text-align:center;">✔</td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Segurança física e perimetral da infraestrutura</td><td style="text-align:center;">✔</td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>SLA de disponibilidade dos recursos contratados</td><td style="text-align:center;">✔</td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Sistema operacional das máquinas virtuais</td><td style="text-align:center;"></td><td style="text-align:center;">✔</td><td style="text-align:center;"></td></tr><tr><td>Instalação, configuração e atualização das aplicações</td><td style="text-align:center;"></td><td style="text-align:center;">✔</td><td style="text-align:center;"></td></tr><tr><td>Gerenciamento do banco de dados (PostgreSQL)</td><td style="text-align:center;"></td><td style="text-align:center;">✔</td><td style="text-align:center;"></td></tr><tr><td>Segurança lógica (usuários, acessos, permissões)</td><td style="text-align:center;"></td><td style="text-align:center;">✔</td><td style="text-align:center;"></td></tr><tr><td>Backups e políticas de retenção de dados</td><td style="text-align:center;"></td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td></tr><tr><td>Monitoramento de aplicações e serviços</td><td style="text-align:center;"></td><td style="text-align:center;">✔</td><td style="text-align:center;">✔</td></tr><tr><td>Atualizações, patches e hardening dos sistemas</td><td style="text-align:center;"></td><td style="text-align:center;">✔</td><td style="text-align:center;"></td></tr><tr><td>Link de internet dedicado com redundância</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Equipamentos de rede local (switch, roteador, cabos)</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Estações de trabalho e periféricos (impressoras, etc.)</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Certificado digital (NF-e / NFC-e) — aquisição e renovação</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Criação de usuário Windows para integração AutoSky</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Configuração e manutenção da VPN local (impressão PDV)</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Repasse do IP da VPN para a equipe de infra (AutoSky)</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Licenças de acesso RDS (CALs) para os usuários</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Treinamento e capacitação dos usuários finais</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr><tr><td>Segurança física das estações e periféricos locais</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✔</td></tr></tbody></table><p><strong>Resumo Executivo</strong></p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Modelo</td><td>Cloud gerenciada (IaaS com camada de gestão)</td></tr><tr><td>Provedor</td><td>Sky.One</td></tr><tr><td>Plataforma</td><td>AutoSky</td></tr><tr><td>Arquitetura</td><td>Distribuída e escalável</td></tr><tr><td>Responsabilidade</td><td>Compartilhada (infraestrutura × aplicação × cliente)</td></tr></tbody></table><hr><h2 id="a-4-configuracao-do-cliente-para-acesso-via-autosky" tabindex="-1">A.4 Configuração do Cliente para Acesso via AutoSky <a class="header-anchor" href="#a-4-configuracao-do-cliente-para-acesso-via-autosky" aria-label="Permalink to &quot;A.4 Configuração do Cliente para Acesso via AutoSky&quot;">​</a></h2><p>Para que os usuários acessem o ambiente cloud, é necessário configurar corretamente cada computador cliente antes do primeiro acesso.</p><h3 id="a-4-1-pasta-de-executaveis" tabindex="-1">A.4.1 Pasta de Executáveis <a class="header-anchor" href="#a-4-1-pasta-de-executaveis" aria-label="Permalink to &quot;A.4.1 Pasta de Executáveis&quot;">​</a></h3><ul><li>A pasta de executáveis do Desbravador deve estar acessível no perfil do usuário dentro do ambiente AutoSky.</li><li>O mapeamento é realizado pelo Analista de Implantação da Desbravador na configuração inicial.</li><li>Atualizações de versão são centralizadas no servidor — nenhuma ação necessária nos clientes.</li></ul><h3 id="a-4-2-base-de-dados" tabindex="-1">A.4.2 Base de Dados <a class="header-anchor" href="#a-4-2-base-de-dados" aria-label="Permalink to &quot;A.4.2 Base de Dados&quot;">​</a></h3><ul><li>A base de dados fica hospedada no servidor cloud. Nenhuma base local é necessária no cliente.</li><li>A string de conexão é configurada pelo Analista de Implantação da Desbravador.</li><li>O cliente não tem acesso direto ao banco de dados — toda comunicação ocorre via camada de aplicação.</li></ul><blockquote><p>ℹ️ <strong>Backup da Base</strong><br> A política de backup é responsabilidade da Desbravador no ambiente cloud. Confirmar frequência, retenção e local de armazenamento dos backups antes do go-live.</p></blockquote><h3 id="a-4-3-certificado-digital-nf-e-nfc-e" tabindex="-1">A.4.3 Certificado Digital (NF-e / NFC-e) <a class="header-anchor" href="#a-4-3-certificado-digital-nf-e-nfc-e" aria-label="Permalink to &quot;A.4.3 Certificado Digital (NF-e / NFC-e)&quot;">​</a></h3><ul><li>Certificado digital A1 (arquivo <code>.pfx</code>) ou A3 (token/smartcard) válido e dentro da validade.</li><li>O certificado deve ser instalado no servidor de aplicação cloud pelo Analista de Implantação.</li><li>A renovação é responsabilidade do cliente — comunicar a Desbravador com <strong>mínimo de 15 dias</strong> de antecedência.</li><li>Para A3 (token físico): verificar viabilidade de redirecionamento USB no AutoSky com a Sky.One antes da contratação.</li></ul><blockquote><p>⚠️ <strong>Atenção — Certificado Digital</strong></p><ul><li>Certificado vencido impede a emissão de documentos fiscais.</li><li>Comunicar a Desbravador com mínimo de 15 dias antes do vencimento.</li><li>Não compartilhar a senha do certificado por canais não seguros.</li></ul></blockquote><h3 id="a-4-4-impressao-de-pdv-—-configuracao-da-maquina-local-e-vpn" tabindex="-1">A.4.4 Impressão de PDV — Configuração da Máquina Local e VPN <a class="header-anchor" href="#a-4-4-impressao-de-pdv-—-configuracao-da-maquina-local-e-vpn" aria-label="Permalink to &quot;A.4.4 Impressão de PDV — Configuração da Máquina Local e VPN&quot;">​</a></h3><p>A impressão de documentos PDV a partir do ambiente cloud requer que as impressoras físicas do hotel sejam acessíveis pelo servidor remoto. São necessários dois procedimentos na máquina onde as impressoras estão conectadas:</p><hr><h4 id="passo-1-—-criacao-do-usuario-windows-dedicado" tabindex="-1">Passo 1 — Criação do Usuário Windows Dedicado <a class="header-anchor" href="#passo-1-—-criacao-do-usuario-windows-dedicado" aria-label="Permalink to &quot;Passo 1 — Criação do Usuário Windows Dedicado&quot;">​</a></h4><p>Crie um usuário Windows específico para a integração com o AutoSky:</p><ol><li>Abra o <strong>Gerenciamento do Computador</strong>: clique com o botão direito em &quot;Este Computador&quot; → &quot;Gerenciar&quot; → &quot;Usuários e Grupos Locais&quot; → &quot;Usuários&quot;.</li><li>Clique com o botão direito na área de usuários → <strong>&quot;Novo usuário...&quot;</strong></li><li>Preencha o nome do usuário (ex.: <code>autosky</code>) e defina uma senha forte. Anote para repasse à infra.</li><li><strong>Desmarque</strong> a opção &quot;O usuário deve alterar a senha no próximo logon&quot;.</li><li><strong>Marque</strong> a opção <strong>&quot;A senha nunca expira&quot;</strong>.</li><li>Clique em &quot;Criar&quot; e depois em &quot;Fechar&quot;.</li><li>Localize o usuário criado → botão direito → &quot;Propriedades&quot; → aba &quot;Membro de&quot;.</li><li>Clique em &quot;Adicionar&quot;, insira <code>Administradores</code> e confirme — o usuário deve ser <strong>Administrador local</strong>.</li><li><strong>Repasse o nome do usuário e a senha para a equipe de infra da Sky.One</strong> para inclusão no script de inicialização do AutoSky.</li></ol><blockquote><p>⚠️ <strong>Segurança do Usuário</strong></p><ul><li>Este usuário deve ser usado exclusivamente para a integração AutoSky.</li><li>Registre as credenciais em local seguro (cofre de senhas). Não envie por e-mail sem criptografia.</li><li>Se a senha precisar ser alterada, comunicar imediatamente a equipe de infra da Sky.One para atualização no script.</li></ul></blockquote><hr><h4 id="passo-2-—-configuracao-da-vpn-na-maquina-local" tabindex="-1">Passo 2 — Configuração da VPN na Máquina Local <a class="header-anchor" href="#passo-2-—-configuracao-da-vpn-na-maquina-local" aria-label="Permalink to &quot;Passo 2 — Configuração da VPN na Máquina Local&quot;">​</a></h4><p>Configure a VPN na mesma máquina onde as impressoras estão conectadas e compartilhadas:</p><ol><li>Acesse: <strong>Configurações → Rede e Internet → VPN → &quot;Adicionar uma conexão VPN&quot;</strong>.</li><li>Preencha os dados da VPN conforme fornecido pela equipe de infra da Sky.One.</li><li>Salve e conecte a VPN.</li><li>Após conectar, verifique o IP atribuído: abra o <strong>Prompt de Comando (CMD)</strong> e execute <code>ipconfig</code>. Localize o adaptador de VPN e anote o <strong>endereço IPv4</strong>.</li><li><strong>Repasse o IP obtido para a equipe de infra da Sky.One</strong> para inclusão no script de inicialização do AutoSky.</li><li>Configure a VPN para conectar automaticamente ao iniciar o Windows (ou conforme orientação da equipe de infra).</li></ol><blockquote><p>ℹ️ <strong>Informações a repassar para a equipe de infra da Sky.One</strong></p><ul><li>✅ Usuário Windows criado (nome e senha)</li><li>✅ IP da VPN atribuído à máquina local</li><li>✅ Nome das impressoras compartilhadas na rede local</li></ul></blockquote><hr><h4 id="resumo-—-configuracao-para-impressao-pdv" tabindex="-1">Resumo — Configuração para Impressão PDV <a class="header-anchor" href="#resumo-—-configuracao-para-impressao-pdv" aria-label="Permalink to &quot;Resumo — Configuração para Impressão PDV&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Item</th><th>Detalhe</th></tr></thead><tbody><tr><td><strong>Máquina</strong></td><td>Computador local onde as impressoras estão conectadas e compartilhadas</td></tr><tr><td><strong>Usuário Windows</strong></td><td>Criar usuário dedicado (ex.: <code>autosky</code>), adicionar ao grupo Administradores, marcar &quot;Senha não expira&quot;</td></tr><tr><td><strong>VPN</strong></td><td>Instalar e configurar VPN na mesma máquina das impressoras; anotar o IP atribuído</td></tr><tr><td><strong>Repasse para infra</strong></td><td>Usuário + senha + IP da VPN → equipe Sky.One (script de inicialização do AutoSky)</td></tr><tr><td><strong>Impressoras</strong></td><td>Garantir que estejam compartilhadas na rede local com driver instalado</td></tr><tr><td><strong>Link mínimo</strong></td><td>10 Mbps simétrico estável · Latência &lt; 50 ms entre cliente e nuvem</td></tr></tbody></table><hr><h2 id="a-5-rede-vpn-e-seguranca" tabindex="-1">A.5 Rede, VPN e Segurança <a class="header-anchor" href="#a-5-rede-vpn-e-seguranca" aria-label="Permalink to &quot;A.5 Rede, VPN e Segurança&quot;">​</a></h2><ul><li>Acesso ao ambiente AutoSky via navegador web ou cliente RDP, conforme configuração da plataforma.</li><li>Recomenda-se link de internet dedicado com contingência (ex.: 4G como backup).</li><li>Firewall perimetral gerenciado pela Sky.One — regras adicionais devem ser solicitadas formalmente.</li><li>Autenticação de usuários: política de senha forte; habilitar MFA se disponível no AutoSky.</li><li>Segregação de acesso por perfil de usuário configurada pela Desbravador.</li><li>Todos os acessos externos devem ser realizados por canais seguros (VPN ou HTTPS).</li></ul><hr><h2 id="a-6-licenciamento-em-ambiente-cloud" tabindex="-1">A.6 Licenciamento em Ambiente Cloud <a class="header-anchor" href="#a-6-licenciamento-em-ambiente-cloud" aria-label="Permalink to &quot;A.6 Licenciamento em Ambiente Cloud&quot;">​</a></h2><ul><li><strong>Windows Server:</strong> conforme modelo contratado com a Sky.One (BYOL ou license included).</li><li><strong>PostgreSQL:</strong> gratuito (licença BSD).</li><li><strong>Desbravador:</strong> definido no contrato comercial — consultar equipe Desbravador.</li><li><strong>CALs (RDS):</strong> responsabilidade do cliente conforme número de usuários simultâneos.</li></ul><hr><h2 id="a-7-responsabilidades-e-slas" tabindex="-1">A.7 Responsabilidades e SLAs <a class="header-anchor" href="#a-7-responsabilidades-e-slas" aria-label="Permalink to &quot;A.7 Responsabilidades e SLAs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Detalhe</th></tr></thead><tbody><tr><td><strong>Disponibilidade da infraestrutura</strong></td><td>SLA definido no contrato com a Sky.One</td></tr><tr><td><strong>Disponibilidade da aplicação</strong></td><td>Monitoramento e resposta a incidentes pela Desbravador em horário comercial</td></tr><tr><td><strong>Janela de manutenção</strong></td><td>Comunicada com antecedência mínima de 48h</td></tr><tr><td><strong>Suporte técnico Desbravador</strong></td><td>Conforme contrato de suporte — consultar equipe comercial</td></tr><tr><td><strong>Suporte infraestrutura Sky.One</strong></td><td>Direto com a Sky.One via canais AutoSky</td></tr><tr><td><strong>Backup</strong></td><td>Política definida pela Desbravador — frequência, retenção e restore a combinar com o cliente</td></tr></tbody></table><hr><h2 id="a-8-contato-e-suporte" tabindex="-1">A.8 Contato e Suporte <a class="header-anchor" href="#a-8-contato-e-suporte" aria-label="Permalink to &quot;A.8 Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><ul><li>Para contratação e implantação em nuvem: equipe comercial Desbravador.</li><li>Para suporte de infraestrutura cloud: acionar diretamente a Sky.One via plataforma AutoSky.</li></ul>',57)])])}const g=a(i,[["render",d]]);export{p as __pageData,g as default};
